const cal=$input.all().map(i=>i.json);
const cfg=$('Read Config').first().json;
const now=new Date();
const today=now.toISOString().split('T')[0];
const isWeekly=now.getDay()===0;
const sd=$getWorkflowStaticData('global');
sd.metrics=[];
sd.isWeekly=isWeekly;

const pub=cal.filter(p=>p.Status==='published'&&p.Instagram_Post_ID);

let posts;
if(isWeekly){
  const wa=new Date(now.getTime()-7*864e5).toISOString().split('T')[0];
  posts=pub.filter(p=>{
    const pubDate=(p.Published_At||'').split('T')[0];
    return pubDate>=wa&&pubDate<=today;
  });
}
else{
  posts=pub.filter(p=>{
    const pubDate=(p.Published_At||'').split('T')[0];
    return pubDate===today;
  });
}

if(!posts.length)return[{json:{skip:true,isWeekly}}];

return posts.map(p=>({
  json:{
    igPostId:p.Instagram_Post_ID,
    postId:p.PostID,
    contentType:p.ContentType,
    pillar:p.Pillar||'',
    hook:p.Hook||'',
    topic:p.Topic||'',
    caption:p.Caption||'',
    scheduledDate:p.ScheduledDate,
    publishedAt:p.Published_At,
    tok:cfg.igAccessToken||'YOUR_IG_ACCESS_TOKEN',
    isWeekly
  }
}));

const sd = $getWorkflowStaticData('global');
const item = $('Insights Loop').first().json;
const resp = $('Fetch Post Insights').first().json;

// Initialize if needed
if (!sd.metrics) {
  sd.metrics = [];
}

const met = {
  postId: item.postId,
  contentType: item.contentType,
  pillar: item.pillar,
  hook: item.hook,
  topic: item.topic,
  date: item.scheduledDate
};

const data = resp.data || [];
data.forEach(m => {
  met[m.name] = m.values ? m.values[0].value : 0;
});

sd.metrics.push(met);

// Return debug info so you can see what's stored
return [{
  json: {
    tracked: true,
    currentCount: sd.metrics.length,
    justAdded: met,
    allStoredMetrics: sd.metrics  // Show everything stored so far
  }
}];

const sd = $getWorkflowStaticData('global');
const m = sd.metrics || [];

// CRITICAL DEBUG
console.log('=== DEEP ANALYSIS DEBUG ===');
console.log('Metrics count:', m.length);
console.log('All metrics:', JSON.stringify(m, null, 2));

// If empty, return error with details
if (m.length === 0) {
  return [{
    json: {
      error: 'No metrics collected',
      sdMetrics: m,
      sdKeys: Object.keys(sd),
      isWeekly: sd.isWeekly
    }
  }];
}

// Rest of your analysis code
const imgs = m.filter(x => x.contentType === 'single_image');
const cars = m.filter(x => x.contentType === 'carousel');
const reels = m.filter(x => x.contentType === 'reel');
const stories = m.filter(x => x.contentType === 'story');

function avg(a, k) {
  if (!a.length) return 0;
  return Math.round(a.reduce((s, x) => s + (x[k] || 0), 0) / a.length);
}

function best(a) {
  if (!a.length) return {};
  return a.reduce((b, x) => (x.total_interactions || 0) > (b.total_interactions || 0) ? x : b, a[0]);
}

const fmts = {
  images: avg(imgs, 'total_interactions'),
  carousels: avg(cars, 'total_interactions'),
  reels: avg(reels, 'total_interactions')
};

const bestFmt = Object.entries(fmts).sort((a, b) => b[1] - a[1])[0][0];

const analysis = {
  images: {
    count: imgs.length,
    avgEng: fmts.images,
    avgReach: avg(imgs, 'reach'),
    best: best(imgs)
  },
  carousels: {
    count: cars.length,
    avgEng: fmts.carousels,
    avgReach: avg(cars, 'reach'),
    best: best(cars)
  },
  reels: {
    count: reels.length,
    avgEng: fmts.reels,
    avgReach: avg(reels, 'reach'),
    best: best(reels)
  },
  stories: {
    count: stories.length,
    avgReach: avg(stories, 'reach')
  },
  totalReach: m.reduce((s, x) => s + (x.reach || 0), 0),
  totalEng: m.reduce((s, x) => s + (x.total_interactions || 0), 0),
  bestFormat: bestFmt,
  allMetrics: m
};

return [{json: analysis}];

