const sd=$getWorkflowStaticData('global');const m=sd.metrics||[];
if(!m.length)return[{json:{message:'📊 No posts published today.',date:new Date().toISOString().split('T')[0]}}];
const p=m[0];const eng=p.engagement||0;const reach=p.impressions||0;const saves=p.saved||0;
const msg='📊 *Today's Post Performance*

Type: '+p.contentType+'
Post: '+p.postId+'
Topic: '+(p.topic||p.hook||'')+'

Reach: '+reach+'
Engagement: '+eng+'
Saves: '+saves+' ⭐
';
return[{json:{message:msg,date:new Date().toISOString().split('T')[0]}}];

const contentType = $json.contentType;

let metrics;
if (contentType === 'reel') {
  // Reels support more metrics including impressions
  metrics = 'plays,reach,likes,comments,shares,saved,total_interactions';
} else if (contentType === 'carousel' || contentType === 'single_image') {
  // Carousels and images - NO impressions in v22.0+
  metrics = 'reach,likes,comments,shares,saved,total_interactions';
} else {
  metrics = 'reach';
}

return {
  json: {
    ...$json,
    metricsToFetch: metrics
  }
};

// Get data from Code in JavaScript node
const codeNodeItems = $('Code in JavaScript').all().map(item => item.json);

// Get data from Track Metrics node
const trackMetricsItems = $('Track Metrics').all().map(item => item.json);

// Stringify both
const codeNodeString = JSON.stringify(codeNodeItems);
const trackMetricsString = JSON.stringify(trackMetricsItems);

// Return exactly two key-value pairs
return [
  {
    json: {
      codeNodeData: codeNodeString,
      trackMetricsData: trackMetricsString
    }
  }
];

// Get full OpenAI response
const response = $input.first().json;

// Extract assistant content
const content = response.choices?.[0]?.message?.content || "";

// Split recommendations and JSON summary
const splitIndex = content.indexOf("JSON summary:");

let recommendations = content;
let summaryObject = {};

if (splitIndex !== -1) {
  recommendations = content.substring(0, splitIndex).trim();

  const jsonPart = content.substring(splitIndex + "JSON summary:".length).trim();

  try {
    summaryObject = JSON.parse(jsonPart);
  } catch (error) {
    summaryObject = { parseError: "Invalid JSON format from AI" };
  }
}

// Return clean structured output
return [
  {
    json: {
      recommendations: recommendations,
      CaptionLength: summaryObject.CaptionLength || 0,
      HashtagCount: summaryObject.HashtagCount || 0,
      CallToAction: summaryObject.CallToAction || "",
      ProductFeatured: summaryObject.ProductFeatured || ""
    }
  }
];

// Build Template Performance data from analytics
const cal = $('Read Calendar').all().map(i => i.json);
const now = new Date().toISOString();
const results = [];

// Group by template + content type + pillar
const templateMap = {};

for (const post of cal) {
  if (!post.PostID || !post.ContentType) continue;
  if (post.Status !== 'published') continue;

  const tpl = post['Preferred Template'] || 'default';
  const ct = (post.ContentType || '').toLowerCase().replace(/\s+/g, '_');
  const pillar = post.Pillar || 'unknown';
  const key = `${tpl}|${ct}|${pillar}`;

  // Calculate performance score
  const eng = parseFloat(post.EngagementRate) || 0;
  const saves = parseInt(post.Saves) || 0;
  const shares = parseInt(post.Shares) || 0;
  const reach = parseInt(post.Reach) || 0;

  // Weighted score: engagement*100 + saves*2 + shares*3
  const score = (eng > 1 ? eng : eng * 100) + saves * 2 + shares * 3;

  if (!templateMap[key]) {
    templateMap[key] = {
      TemplateID: tpl,
      TemplateName: tpl.replace(/\(Id:[^)]+\)/i, '').replace(/\([a-f0-9\-]{36}\)/i, '').trim(),
      ContentType: ct,
      Pillar: pillar,
      scores: [],
      timesUsed: 0
    };
  }

  templateMap[key].scores.push(score);
  templateMap[key].timesUsed++;
}

// Calculate averages and output
for (const [key, data] of Object.entries(templateMap)) {
  const avgScore = data.scores.reduce((a, b) => a + b, 0) / data.scores.length;
  results.push({
    json: {
      TemplateID: data.TemplateID,
      TemplateName: data.TemplateName,
      ContentType: data.ContentType,
      Pillar: data.Pillar,
      PerformanceScore: avgScore.toFixed(2),
      TimesUsed: data.timesUsed,
      LastUpdated: now
    }
  });
}

return results.length > 0 ? results : [{ json: { skip: true } }];
